from flask import Flask, request, jsonify, send_file
from pathlib import Path
import os
import mimetypes

app = Flask(__name__)

# Base directory for user files
BASE_DIR = Path('./user_files').resolve()
BASE_DIR.mkdir(exist_ok=True)

def validate_path(user_path):
    """
    Validate and canonicalize user-provided path to prevent path traversal.
    Returns the resolved full path if valid, None otherwise.
    """
    # Reject absolute paths
    if os.path.isabs(user_path):
        return None
    
    # Construct full path and resolve it
    try:
        full_path = (BASE_DIR / user_path).resolve()
    except (ValueError, OSError):
        return None
    
    # Verify the resolved path is within BASE_DIR
    try:
        full_path.relative_to(BASE_DIR)
    except ValueError:
        return None
    
    return full_path

@app.route('/api/list', methods=['GET'])
def list_directory():
    """List contents of a directory"""
    user_path = request.args.get('path', '')
    
    full_path = validate_path(user_path)
    if full_path is None:
        return jsonify({'error': 'Invalid path'}), 400
    
    if not full_path.exists():
        return jsonify({'error': 'Path does not exist'}), 404
    
    if not full_path.is_dir():
        return jsonify({'error': 'Path is not a directory'}), 400
    
    try:
        items = []
        for item in full_path.iterdir():
            items.append({
                'name': item.name,
                'type': 'directory' if item.is_dir() else 'file',
                'size': item.stat().st_size if item.is_file() else None,
                'modified': item.stat().st_mtime
            })
        
        return jsonify({
            'path': str(full_path.relative_to(BASE_DIR)),
            'items': items
        })
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403

@app.route('/api/download', methods=['GET'])
def download_file():
    """Download a file"""
    user_path = request.args.get('path', '')
    
    full_path = validate_path(user_path)
    if full_path is None:
        return jsonify({'error': 'Invalid path'}), 400
    
    if not full_path.exists():
        return jsonify({'error': 'File does not exist'}), 404
    
    if not full_path.is_file():
        return jsonify({'error': 'Path is not a file'}), 400
    
    try:
        return send_file(
            full_path,
            as_attachment=True,
            download_name=full_path.name
        )
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403

@app.route('/api/info', methods=['GET'])
def get_file_info():
    """Get information about a file or directory"""
    user_path = request.args.get('path', '')
    
    full_path = validate_path(user_path)
    if full_path is None:
        return jsonify({'error': 'Invalid path'}), 400
    
    if not full_path.exists():
        return jsonify({'error': 'Path does not exist'}), 404
    
    try:
        stat_info = full_path.stat()
        
        info = {
            'name': full_path.name,
            'path': str(full_path.relative_to(BASE_DIR)),
            'type': 'directory' if full_path.is_dir() else 'file',
            'size': stat_info.st_size,
            'created': stat_info.st_ctime,
            'modified': stat_info.st_mtime,
            'accessed': stat_info.st_atime
        }
        
        if full_path.is_file():
            mime_type, _ = mimetypes.guess_type(str(full_path))
            info['mime_type'] = mime_type
        
        return jsonify(info)
    except PermissionError:
        return jsonify({'error': 'Permission denied'}), 403

if __name__ == '__main__':
    app.run(debug=True)